// ============================================
// AGREGUJ META ADS — PODZIAŁ PLATFORM
// ============================================

const data  = $input.first().json;
const dates = $('📆 Przygotuj Daty1').first().json;

// ── Helpers ──────────────────────────────────
function safeNum(v)   { return parseInt(v)   || 0; }
function safeFloat(v) { return parseFloat(v) || 0; }

function getAction(actions, type) {
  if (!Array.isArray(actions)) return 0;
  const found = actions.find(a => a.action_type === type);
  return found ? safeFloat(found.value) : 0;
}

// ── Pobierz wiersze ───────────────────────────
const rows = data?.data || [];

// ── Mapy agregacji ────────────────────────────
const platformMap = {};
const deviceMap   = {};
const combMap     = {};  // platform + device łącznie

// ── Liczniki globalne ─────────────────────────
let totalSpend       = 0;
let totalImpressions = 0;
let totalClicks      = 0;
let totalReach       = 0;
let totalPurchases   = 0;
let totalLeads       = 0;

// ── Pętla po wierszach ────────────────────────
for (const row of rows) {
  const platform  = row.publisher_platform || 'unknown';
  const device    = row.device_platform    || 'unknown';
  const combKey   = `${platform} / ${device}`;

  const spend       = safeFloat(row.spend);
  const impressions = safeNum(row.impressions);
  const clicks      = safeNum(row.clicks);
  const reach       = safeNum(row.reach);
  const actions     = row.actions || [];

  const purchases = getAction(actions, 'purchase');
  const leads     = getAction(actions, 'lead');
  const videoViews= getAction(actions, 'video_view');
  const linkClicks= getAction(actions, 'link_click');
  const addToCart = getAction(actions, 'add_to_cart');

  // Globalne
  totalSpend       += spend;
  totalImpressions += impressions;
  totalClicks      += clicks;
  totalReach       += reach;
  totalPurchases   += purchases;
  totalLeads       += leads;

  // ── Agregacja per PLATFORMA ──────────────────
  if (!platformMap[platform]) {
    platformMap[platform] = {
      spend: 0, impressions: 0, clicks: 0,
      reach: 0, purchases: 0, leads: 0,
      videoViews: 0, linkClicks: 0, addToCart: 0
    };
  }
  platformMap[platform].spend       += spend;
  platformMap[platform].impressions += impressions;
  platformMap[platform].clicks      += clicks;
  platformMap[platform].reach       += reach;
  platformMap[platform].purchases   += purchases;
  platformMap[platform].leads       += leads;
  platformMap[platform].videoViews  += videoViews;
  platformMap[platform].linkClicks  += linkClicks;
  platformMap[platform].addToCart   += addToCart;

  // ── Agregacja per URZĄDZENIE ──────────────────
  if (!deviceMap[device]) {
    deviceMap[device] = {
      spend: 0, impressions: 0, clicks: 0,
      reach: 0, purchases: 0, leads: 0
    };
  }
  deviceMap[device].spend       += spend;
  deviceMap[device].impressions += impressions;
  deviceMap[device].clicks      += clicks;
  deviceMap[device].reach       += reach;
  deviceMap[device].purchases   += purchases;
  deviceMap[device].leads       += leads;

  // ── Agregacja PLATFORMA + URZĄDZENIE ──────────
  if (!combMap[combKey]) {
    combMap[combKey] = {
      platform, device,
      spend: 0, impressions: 0, clicks: 0,
      reach: 0, purchases: 0, leads: 0
    };
  }
  combMap[combKey].spend       += spend;
  combMap[combKey].impressions += impressions;
  combMap[combKey].clicks      += clicks;
  combMap[combKey].reach       += reach;
  combMap[combKey].purchases   += purchases;
  combMap[combKey].leads       += leads;
}

// ── Wzbogać platformy o wskaźniki ────────────
const platformStats = {};

for (const [name, d] of Object.entries(platformMap)) {
  const ctr      = d.impressions > 0
    ? ((d.clicks / d.impressions) * 100).toFixed(2) : '0.00';
  const cpm      = d.impressions > 0
    ? ((d.spend / d.impressions) * 1000).toFixed(2)  : '0.00';
  const cpc      = d.clicks > 0
    ? (d.spend / d.clicks).toFixed(2)                : '0.00';
  const cpp      = d.reach > 0
    ? (d.spend / d.reach * 1000).toFixed(2)          : '0.00';
  const convRate = d.clicks > 0
    ? (((d.purchases + d.leads) / d.clicks) * 100).toFixed(2) : '0.00';
  const cpa      = (d.purchases + d.leads) > 0
    ? (d.spend / (d.purchases + d.leads)).toFixed(2) : '0.00';

  // Udział procentowy
  const spendPct = totalSpend > 0
    ? ((d.spend / totalSpend) * 100).toFixed(1)       : '0.0';
  const impPct   = totalImpressions > 0
    ? ((d.impressions / totalImpressions) * 100).toFixed(1) : '0.0';
  const clickPct = totalClicks > 0
    ? ((d.clicks / totalClicks) * 100).toFixed(1)     : '0.0';

  // Emoji platformy
  const icons = {
    facebook:         '🔵',
    instagram:        '🟣',
    audience_network: '🌐',
    messenger:        '💬'
  };

  platformStats[name] = {
    icon:        icons[name] || '📢',
    label:       name.charAt(0).toUpperCase() + name.slice(1).replace('_', ' '),

    // Wyniki
    spend:       d.spend.toFixed(2),
    impressions: d.impressions,
    clicks:      d.clicks,
    reach:       d.reach,
    purchases:   Math.round(d.purchases),
    leads:       Math.round(d.leads),
    videoViews:  Math.round(d.videoViews),
    addToCart:   Math.round(d.addToCart),

    // Wskaźniki
    ctr,
    cpm,
    cpc,
    cpp,
    convRate,
    cpa,

    // Udziały %
    spendPct,
    impPct,
    clickPct
  };
}

// ── Wzbogać urządzenia o wskaźniki ───────────
const deviceStats = {};

for (const [name, d] of Object.entries(deviceMap)) {
  const ctr      = d.impressions > 0
    ? ((d.clicks / d.impressions) * 100).toFixed(2) : '0.00';
  const cpm      = d.impressions > 0
    ? ((d.spend / d.impressions) * 1000).toFixed(2)  : '0.00';
  const cpc      = d.clicks > 0
    ? (d.spend / d.clicks).toFixed(2)                : '0.00';
  const spendPct = totalSpend > 0
    ? ((d.spend / totalSpend) * 100).toFixed(1)      : '0.0';

  const deviceIcons = {
    mobile:  '📱',
    desktop: '🖥️',
    tablet:  '📲'
  };

  deviceStats[name] = {
    icon:        deviceIcons[name] || '💻',
    label:       name.charAt(0).toUpperCase() + name.slice(1),
    spend:       d.spend.toFixed(2),
    impressions: d.impressions,
    clicks:      d.clicks,
    reach:       d.reach,
    purchases:   Math.round(d.purchases),
    leads:       Math.round(d.leads),
    ctr,
    cpm,
    cpc,
    spendPct
  };
}

// ── Wzbogać kombinacje platforma+urządzenie ───
const combinedStats = [];

for (const [key, d] of Object.entries(combMap)) {
  const ctr      = d.impressions > 0
    ? ((d.clicks / d.impressions) * 100).toFixed(2) : '0.00';
  const spendPct = totalSpend > 0
    ? ((d.spend / totalSpend) * 100).toFixed(1)     : '0.0';

  combinedStats.push({
    combination: key,
    platform:    d.platform,
    device:      d.device,
    spend:       d.spend.toFixed(2),
    impressions: d.impressions,
    clicks:      d.clicks,
    reach:       d.reach,
    purchases:   Math.round(d.purchases),
    leads:       Math.round(d.leads),
    ctr,
    spendPct
  });
}

// Sortuj kombinacje wg wydatków
combinedStats.sort((a, b) => parseFloat(b.spend) - parseFloat(a.spend));

// ── Wyznacz najlepszą platformę ───────────────
const bestPlatformByROAS = Object.entries(platformStats)
  .filter(([, d]) => parseInt(d.purchases) > 0)
  .sort((a, b) => {
    const roasA = parseFloat(a[1].spend) > 0
      ? parseInt(a[1].purchases) / parseFloat(a[1].spend) : 0;
    const roasB = parseFloat(b[1].spend) > 0
      ? parseInt(b[1].purchases) / parseFloat(b[1].spend) : 0;
    return roasB - roasA;
  })[0]?.[0] || 'N/A';

const bestPlatformByCTR = Object.entries(platformStats)
  .sort((a, b) => parseFloat(b[1].ctr) - parseFloat(a[1].ctr))[0]?.[0] || 'N/A';

const bestDeviceByConv = Object.entries(deviceStats)
  .sort((a, b) => parseInt(b[1].purchases) - parseInt(a[1].purchases))[0]?.[0] || 'N/A';

console.log(`Meta Platformy: ${Object.keys(platformStats).length} platform | Urządzenia: ${Object.keys(deviceStats).length}`);

return [{
  json: {
    ...dates,

    metaPlatforms: {
      // Globalne sumy
      totalSpend:       totalSpend.toFixed(2),
      totalImpressions,
      totalClicks,
      totalReach,
      totalPurchases:   Math.round(totalPurchases),
      totalLeads:       Math.round(totalLeads),

      // Globalne wskaźniki
      overallCTR: totalImpressions > 0
        ? ((totalClicks / totalImpressions) * 100).toFixed(2) : '0.00',
      overallCPM: totalImpressions > 0
        ? ((totalSpend / totalImpressions) * 1000).toFixed(2)  : '0.00',
      overallCPC: totalClicks > 0
        ? (totalSpend / totalClicks).toFixed(2)                : '0.00',

      // Wyniki per platforma
      platformBreakdown: platformStats,

      // Wyniki per urządzenie
      deviceBreakdown: deviceStats,

      // Kombinacje platforma + urządzenie
      combinedBreakdown: combinedStats,

      // Najlepsze
      bestPlatformByROAS,
      bestPlatformByCTR,
      bestDeviceByConv,

      // Liczba platform
      platformCount: Object.keys(platformStats).length,
      deviceCount:   Object.keys(deviceStats).length
    }
  }
}];

