// AGREGUJ DANE Z METRICOOL
// ============================================

const data  = $input.first().json;
const dates = $('📆 Przygotuj Daty1').first().json;

const networks = data?.data?.networks || data?.networks || data || {};

function safeNum(val)   { return parseInt(val)   || 0; }
function safeFloat(val) { return parseFloat(val) || 0; }

const socialData       = {};
let totalReach         = 0;
let totalImpressions   = 0;
let totalEngagements   = 0;
let totalFollowers     = 0;
let totalPosts         = 0;

const networkNames = ['instagram', 'facebook', 'linkedin', 'twitter', 'tiktok'];

for (const net of networkNames) {
  const netData          = networks[net] || {};
  const reach            = safeNum(netData.reach            || netData.totalReach);
  const impressions      = safeNum(netData.impressions      || netData.totalImpressions);
  const engagements      = safeNum(netData.engagements      || netData.totalEngagements || netData.interactions);
  const followers        = safeNum(netData.followers        || netData.totalFollowers);
  const followersGrowth  = safeNum(netData.followersGrowth  || netData.newFollowers);
  const posts            = safeNum(netData.posts            || netData.totalPosts || netData.publications);
  const engRate          = followers > 0 ? ((engagements / followers) * 100) : 0;

  if (reach > 0 || followers > 0) {
    socialData[net] = {
      reach, impressions, engagements, followers, followersGrowth, posts,
      engagementRate: engRate.toFixed(2)
    };
    totalReach       += reach;
    totalImpressions += impressions;
    totalEngagements += engagements;
    totalFollowers   += followers;
    totalPosts       += posts;
  }
}

const avgEngRate = totalFollowers > 0
  ? ((totalEngagements / totalFollowers) * 100).toFixed(2) : '0.00';

const bestPosts = data?.data?.bestPosts || data?.bestPosts || [];

return [{
  json: {
    ...dates,
    metricool: {
      totalReach,
      totalImpressions,
      totalEngagements,
      totalFollowers,
      totalPosts,
      avgEngagementRate: parseFloat(avgEngRate),
      networks: socialData,
      bestPosts: bestPosts.slice(0, 3).map(p => ({
        network:     p.network || 'unknown',
        content:     (p.text || p.content || '').substring(0, 100),
        reach:       safeNum(p.reach),
        engagements: safeNum(p.engagements),
        date:        p.date || p.publishedAt
      }))
    }
  }
}];

