const err = $input.first().json;
console.error('WORKFLOW ERROR:', JSON.stringify(err));
return [{
  json: {
    error:     true,
    message:   err?.message || err?.error?.message || 'Unknown error',
    timestamp: new Date().toISOString(),
    workflow:  'Raport Miesięczny z Meta Ads'
  }
}];

// ============================================
// AGREGUJ META ADS — KAMPANIE
// ============================================

const data  = $input.first().json;
const dates = $('📆 Przygotuj Daty1').first().json;

// ── Helper functions ────────────────────────
function safeNum(v)   { return parseInt(v)   || 0; }
function safeFloat(v) { return parseFloat(v) || 0; }

function getAction(actions, type) {
  if (!Array.isArray(actions)) return 0;
  const found = actions.find(a => a.action_type === type);
  return found ? safeFloat(found.value) : 0;
}

// ── Pobierz wiersze kampanii ─────────────────
const rows = data?.data || [];

// ── Liczniki globalne ────────────────────────
let totalSpend          = 0;
let totalImpressions    = 0;
let totalClicks         = 0;
let totalReach          = 0;
let totalFrequencySum   = 0;
let totalPurchases      = 0;
let totalPurchaseValue  = 0;
let totalLeads          = 0;
let totalLinkClicks     = 0;
let totalVideoViews     = 0;
let totalAddToCart      = 0;
let totalInitCheckout   = 0;
let totalLandingViews   = 0;

// ── Lista kampanii ───────────────────────────
const campaigns = [];

// ── Pętla po kampaniach ──────────────────────
for (const row of rows) {
  const spend       = safeFloat(row.spend);
  const impressions = safeNum(row.impressions);
  const clicks      = safeNum(row.clicks);
  const reach       = safeNum(row.reach);
  const frequency   = safeFloat(row.frequency);
  const ctr         = safeFloat(row.ctr);
  const cpc         = safeFloat(row.cpc);
  const cpm         = safeFloat(row.cpm);
  const cpp         = safeFloat(row.cpp);

  const actions      = row.actions       || [];
  const actionValues = row.action_values || [];

  // Akcje konwersji
  const purchases      = getAction(actions,      'purchase');
  const purchaseValue  = getAction(actionValues, 'purchase');
  const leads          = getAction(actions,      'lead');
  const linkClicks     = getAction(actions,      'link_click');
  const videoViews     = getAction(actions,      'video_view');
  const addToCart      = getAction(actions,      'add_to_cart');
  const initCheckout   = getAction(actions,      'initiate_checkout');
  const landingViews   = getAction(actions,      'landing_page_view');

  // Sumy globalne
  totalSpend         += spend;
  totalImpressions   += impressions;
  totalClicks        += clicks;
  totalReach         += reach;
  totalFrequencySum  += frequency;
  totalPurchases     += purchases;
  totalPurchaseValue += purchaseValue;
  totalLeads         += leads;
  totalLinkClicks    += linkClicks;
  totalVideoViews    += videoViews;
  totalAddToCart     += addToCart;
  totalInitCheckout  += initCheckout;
  totalLandingViews  += landingViews;

  // Wskaźniki per kampania
  const campROAS = spend > 0
    ? (purchaseValue / spend).toFixed(2)
    : '0.00';

  const totalActions = purchases + leads;
  const campCPA = totalActions > 0
    ? (spend / totalActions).toFixed(2)
    : '0.00';

  const campCTR = impressions > 0
    ? ((clicks / impressions) * 100).toFixed(2)
    : ctr.toFixed(2);

  const campCPM = impressions > 0
    ? ((spend / impressions) * 1000).toFixed(2)
    : cpm.toFixed(2);

  // Click-through rate do landing page
  const lpvRate = clicks > 0
    ? ((landingViews / clicks) * 100).toFixed(2)
    : '0.00';

  // Add-to-cart rate
  const atcRate = landingViews > 0
    ? ((addToCart / landingViews) * 100).toFixed(2)
    : '0.00';

  // Checkout rate
  const checkoutRate = addToCart > 0
    ? ((initCheckout / addToCart) * 100).toFixed(2)
    : '0.00';

  // Purchase rate z checkout
  const purchaseRate = initCheckout > 0
    ? ((purchases / initCheckout) * 100).toFixed(2)
    : '0.00';

  if (row.campaign_name || row.campaign_id) {
    campaigns.push({
      id:            row.campaign_id   || 'N/A',
      name:          row.campaign_name || 'Nieznana',
      objective:     row.objective     || 'N/A',
      status:        row.status        || 'ACTIVE',

      // Zasięg i wyświetlenia
      spend:         spend.toFixed(2),
      impressions,
      clicks,
      reach,
      frequency:     frequency.toFixed(2),

      // Wskaźniki efektywności
      ctr:           campCTR,
      cpc:           cpc.toFixed(2),
      cpm:           campCPM,
      cpp:           cpp.toFixed(2),

      // Konwersje
      purchases:     Math.round(purchases),
      purchaseValue: purchaseValue.toFixed(2),
      leads:         Math.round(leads),
      linkClicks:    Math.round(linkClicks),
      videoViews:    Math.round(videoViews),
      addToCart:     Math.round(addToCart),
      initCheckout:  Math.round(initCheckout),
      landingViews:  Math.round(landingViews),

      // Wskaźniki lejka
      lpvRate,
      atcRate,
      checkoutRate,
      purchaseRate,

      // Podsumowanie
      roas:          campROAS,
      cpa:           campCPA,
      totalConversions: Math.round(purchases + leads)
    });
  }
}

// ── Globalne wskaźniki ───────────────────────
const overallCTR  = totalImpressions > 0
  ? ((totalClicks / totalImpressions) * 100).toFixed(2)
  : '0.00';

const overallCPC  = totalClicks > 0
  ? (totalSpend / totalClicks).toFixed(2)
  : '0.00';

const overallCPM  = totalImpressions > 0
  ? ((totalSpend / totalImpressions) * 1000).toFixed(2)
  : '0.00';

const overallCPP  = totalReach > 0
  ? (totalSpend / totalReach * 1000).toFixed(2)
  : '0.00';

const overallROAS = totalSpend > 0
  ? (totalPurchaseValue / totalSpend).toFixed(2)
  : '0.00';

const totalConversions = totalPurchases + totalLeads;

const overallCPA  = totalConversions > 0
  ? (totalSpend / totalConversions).toFixed(2)
  : '0.00';

const avgFrequency = campaigns.length > 0
  ? (totalFrequencySum / campaigns.length).toFixed(2)
  : '0.00';

// ── Lejek sprzedażowy ────────────────────────
const funnelData = {
  zasieg:              Math.round(totalReach),
  wyswietlenia:        Math.round(totalImpressions),
  klikniecia:          Math.round(totalClicks),
  odslonyLanding:      Math.round(totalLandingViews),
  dodaniaDoKoszyka:    Math.round(totalAddToCart),
  rozpoczeciaZakupu:   Math.round(totalInitCheckout),
  zakupy:              Math.round(totalPurchases),
  // Konwersje lejka %
  ctr_pct:             overallCTR,
  lpv_rate_pct:        totalClicks > 0
    ? ((totalLandingViews / totalClicks) * 100).toFixed(2) : '0.00',
  atc_rate_pct:        totalLandingViews > 0
    ? ((totalAddToCart / totalLandingViews) * 100).toFixed(2) : '0.00',
  checkout_rate_pct:   totalAddToCart > 0
    ? ((totalInitCheckout / totalAddToCart) * 100).toFixed(2) : '0.00',
  purchase_rate_pct:   totalInitCheckout > 0
    ? ((totalPurchases / totalInitCheckout) * 100).toFixed(2) : '0.00'
};

// ── Sortowania ───────────────────────────────
const topBySpend = [...campaigns]
  .sort((a, b) => parseFloat(b.spend) - parseFloat(a.spend))
  .slice(0, 5);

const topByROAS = [...campaigns]
  .filter(c => parseFloat(c.roas) > 0)
  .sort((a, b) => parseFloat(b.roas) - parseFloat(a.roas))
  .slice(0, 5);

const topByConversions = [...campaigns]
  .sort((a, b) => b.totalConversions - a.totalConversions)
  .slice(0, 5);

// ── Podział wg celu kampanii ─────────────────
const objectiveMap = {};
for (const c of campaigns) {
  const obj = c.objective || 'UNKNOWN';
  if (!objectiveMap[obj]) {
    objectiveMap[obj] = {
      count:       0,
      spend:       0,
      impressions: 0,
      clicks:      0,
      purchases:   0,
      leads:       0
    };
  }
  objectiveMap[obj].count       += 1;
  objectiveMap[obj].spend       += parseFloat(c.spend);
  objectiveMap[obj].impressions += c.impressions;
  objectiveMap[obj].clicks      += c.clicks;
  objectiveMap[obj].purchases   += c.purchases;
  objectiveMap[obj].leads       += c.leads;
}

// Zaokrąglij sumy celów
const objectiveBreakdown = {};
for (const [obj, d] of Object.entries(objectiveMap)) {
  objectiveBreakdown[obj] = {
    count:       d.count,
    spend:       d.spend.toFixed(2),
    impressions: d.impressions,
    clicks:      d.clicks,
    purchases:   d.purchases,
    leads:       d.leads,
    ctr:         d.impressions > 0
      ? ((d.clicks / d.impressions) * 100).toFixed(2) : '0.00',
    spendPct:    totalSpend > 0
      ? ((d.spend / totalSpend) * 100).toFixed(1) : '0.0'
  };
}

console.log(`Meta Kampanie: ${campaigns.length} kampanii | Wydatki: ${totalSpend.toFixed(2)} PLN | ROAS: ${overallROAS}`);

return [{
  json: {
    ...dates,

    metaCampaigns: {
      // Główne KPI
      totalSpend:          totalSpend.toFixed(2),
      totalImpressions,
      totalClicks,
      totalReach,
      totalPurchases:      Math.round(totalPurchases),
      totalPurchaseValue:  totalPurchaseValue.toFixed(2),
      totalLeads:          Math.round(totalLeads),
      totalLinkClicks:     Math.round(totalLinkClicks),
      totalVideoViews:     Math.round(totalVideoViews),
      totalAddToCart:      Math.round(totalAddToCart),
      totalInitCheckout:   Math.round(totalInitCheckout),
      totalLandingViews:   Math.round(totalLandingViews),
      totalConversions:    Math.round(totalConversions),

      // Wskaźniki efektywności
      overallCTR,
      overallCPC,
      overallCPM,
      overallCPP,
      overallROAS,
      overallCPA,
      avgFrequency,

      // Struktura
      activeCampaigns:    campaigns.length,

      // Rankingi
      topBySpend,
      topByROAS,
      topByConversions,
      allCampaigns: campaigns,

      // Podziały
      objectiveBreakdown,
      funnelData
    }
  }
}];

// ============================================
// AGREGUJ META ADS — DEMOGRAFIA (WIEK + PŁEĆ)
// ============================================

const data  = $input.first().json;
const dates = $('📆 Przygotuj Daty1').first().json;

// ── Helpers ──────────────────────────────────
function safeNum(v)   { return parseInt(v)   || 0; }
function safeFloat(v) { return parseFloat(v) || 0; }

function getAction(actions, type) {
  if (!Array.isArray(actions)) return 0;
  const found = actions.find(a => a.action_type === type);
  return found ? safeFloat(found.value) : 0;
}

// ── Pobierz wiersze ───────────────────────────
const rows = data?.data || [];

// ── Mapy agregacji ────────────────────────────
const ageMap     = {};
const genderMap  = {};
const segmentMap = {}; // wiek + płeć razem

// ── Liczniki globalne ─────────────────────────
let totalSpend       = 0;
let totalImpressions = 0;
let totalClicks      = 0;
let totalReach       = 0;
let totalPurchases   = 0;
let totalLeads       = 0;

// ── Kolejność grup wiekowych ──────────────────
const ageOrder = ['13-17','18-24','25-34','35-44','45-54','55-64','65+'];

// ── Pętla po wierszach ────────────────────────
for (const row of rows) {
  const age    = row.age    || 'unknown';
  const gender = row.gender || 'unknown';
  const segKey = `${age} / ${gender}`;

  const spend       = safeFloat(row.spend);
  const impressions = safeNum(row.impressions);
  const clicks      = safeNum(row.clicks);
  const reach       = safeNum(row.reach);
  const actions     = row.actions || [];

  const purchases  = getAction(actions, 'purchase');
  const leads      = getAction(actions, 'lead');
  const addToCart  = getAction(actions, 'add_to_cart');
  const videoViews = getAction(actions, 'video_view');
  const linkClicks = getAction(actions, 'link_click');

  // Globalne
  totalSpend       += spend;
  totalImpressions += impressions;
  totalClicks      += clicks;
  totalReach       += reach;
  totalPurchases   += purchases;
  totalLeads       += leads;

  // ── Agregacja per WIEK ────────────────────────
  if (!ageMap[age]) {
    ageMap[age] = {
      spend: 0, impressions: 0, clicks: 0,
      reach: 0, purchases: 0, leads: 0,
      addToCart: 0, videoViews: 0, linkClicks: 0
    };
  }
  ageMap[age].spend       += spend;
  ageMap[age].impressions += impressions;
  ageMap[age].clicks      += clicks;
  ageMap[age].reach       += reach;
  ageMap[age].purchases   += purchases;
  ageMap[age].leads       += leads;
  ageMap[age].addToCart   += addToCart;
  ageMap[age].videoViews  += videoViews;
  ageMap[age].linkClicks  += linkClicks;

  // ── Agregacja per PŁEĆ ────────────────────────
  if (!genderMap[gender]) {
    genderMap[gender] = {
      spend: 0, impressions: 0, clicks: 0,
      reach: 0, purchases: 0, leads: 0,
      addToCart: 0, videoViews: 0, linkClicks: 0
    };
  }
  genderMap[gender].spend       += spend;
  genderMap[gender].impressions += impressions;
  genderMap[gender].clicks      += clicks;
  genderMap[gender].reach       += reach;
  genderMap[gender].purchases   += purchases;
  genderMap[gender].leads       += leads;
  genderMap[gender].addToCart   += addToCart;
  genderMap[gender].videoViews  += videoViews;
  genderMap[gender].linkClicks  += linkClicks;

  // ── Agregacja WIEK + PŁEĆ ─────────────────────
  if (!segmentMap[segKey]) {
    segmentMap[segKey] = {
      age, gender,
      spend: 0, impressions: 0, clicks: 0,
      reach: 0, purchases: 0, leads: 0, addToCart: 0
    };
  }
  segmentMap[segKey].spend       += spend;
  segmentMap[segKey].impressions += impressions;
  segmentMap[segKey].clicks      += clicks;
  segmentMap[segKey].reach       += reach;
  segmentMap[segKey].purchases   += purchases;
  segmentMap[segKey].leads       += leads;
  segmentMap[segKey].addToCart   += addToCart;
}

// ── Wzbogać dane wiekowe ──────────────────────
const ageStats = {};

for (const [age, d] of Object.entries(ageMap)) {
  const ctr       = d.impressions > 0
    ? ((d.clicks / d.impressions) * 100).toFixed(2)         : '0.00';
  const cpm       = d.impressions > 0
    ? ((d.spend / d.impressions) * 1000).toFixed(2)          : '0.00';
  const cpc       = d.clicks > 0
    ? (d.spend / d.clicks).toFixed(2)                        : '0.00';
  const convRate  = d.clicks > 0
    ? (((d.purchases + d.leads) / d.clicks) * 100).toFixed(2): '0.00';
  const cpa       = (d.purchases + d.leads) > 0
    ? (d.spend / (d.purchases + d.leads)).toFixed(2)         : '0.00';
  const atcRate   = d.clicks > 0
    ? ((d.addToCart / d.clicks) * 100).toFixed(2)            : '0.00';

  const spendPct  = totalSpend > 0
    ? ((d.spend / totalSpend) * 100).toFixed(1)              : '0.0';
  const reachPct  = totalReach > 0
    ? ((d.reach / totalReach) * 100).toFixed(1)              : '0.0';

  ageStats[age] = {
    // Wyniki
    spend:       d.spend.toFixed(2),
    impressions: d.impressions,
    clicks:      d.clicks,
    reach:       d.reach,
    purchases:   Math.round(d.purchases),
    leads:       Math.round(d.leads),
    addToCart:   Math.round(d.addToCart),
    videoViews:  Math.round(d.videoViews),

    // Wskaźniki
    ctr,
    cpm,
    cpc,
    convRate,
    cpa,
    atcRate,

    // Udziały
    spendPct,
    reachPct
  };
}

// Posortuj wg kolejności wiekowej
const ageSorted = {};
const ageKeys   = Object.keys(ageStats)
  .sort((a, b) => {
    const ia = ageOrder.indexOf(a);
    const ib = ageOrder.indexOf(b);
    if (ia === -1 && ib === -1) return a.localeCompare(b);
    if (ia === -1) return 1;
    if (ib === -1) return -1;
    return ia - ib;
  });

for (const k of ageKeys) ageSorted[k] = ageStats[k];

// ── Wzbogać dane płciowe ──────────────────────
const genderLabels = {
  male:    'Mężczyźni',
  female:  'Kobiety',
  unknown: 'Nieznana'
};

const genderStats = {};

for (const [gender, d] of Object.entries(genderMap)) {
  const label     = genderLabels[gender] || gender;
  const ctr       = d.impressions > 0
    ? ((d.clicks / d.impressions) * 100).toFixed(2)         : '0.00';
  const cpm       = d.impressions > 0
    ? ((d.spend / d.impressions) * 1000).toFixed(2)          : '0.00';
  const cpc       = d.clicks > 0
    ? (d.spend / d.clicks).toFixed(2)                        : '0.00';
  const convRate  = d.clicks > 0
    ? (((d.purchases + d.leads) / d.clicks) * 100).toFixed(2): '0.00';
  const cpa       = (d.purchases + d.leads) > 0
    ? (d.spend / (d.purchases + d.leads)).toFixed(2)         : '0.00';

  const spendPct  = totalSpend > 0
    ? ((d.spend / totalSpend) * 100).toFixed(1)              : '0.0';
  const reachPct  = totalReach > 0
    ? ((d.reach / totalReach) * 100).toFixed(1)              : '0.0';

  genderStats[label] = {
    genderKey: gender,

    // Wyniki
    spend:       d.spend.toFixed(2),
    impressions: d.impressions,
    clicks:      d.clicks,
    reach:       d.reach,
    purchases:   Math.round(d.purchases),
    leads:       Math.round(d.leads),
    addToCart:   Math.round(d.addToCart),
    videoViews:  Math.round(d.videoViews),

    // Wskaźniki
    ctr,
    cpm,
    cpc,
    convRate,
    cpa,

    // Udziały
    spendPct,
    reachPct
  };
}

// ── Segmenty wiek + płeć ──────────────────────
const segments = Object.values(segmentMap)
  .map(d => {
    const ctr  = d.impressions > 0
      ? ((d.clicks / d.impressions) * 100).toFixed(2) : '0.00';
    const cpa  = (d.purchases + d.leads) > 0
      ? (d.spend / (d.purchases + d.leads)).toFixed(2) : '0.00';
    const spendPct = totalSpend > 0
      ? ((d.spend / totalSpend) * 100).toFixed(1) : '0.0';

    return {
      segment:     `${d.age} / ${genderLabels[d.gender] || d.gender}`,
      age:         d.age,
      gender:      genderLabels[d.gender] || d.gender,
      spend:       d.spend.toFixed(2),
      impressions: d.impressions,
      clicks:      d.clicks,
      reach:       d.reach,
      purchases:   Math.round(d.purchases),
      leads:       Math.round(d.leads),
      addToCart:   Math.round(d.addToCart),
      ctr,
      cpa,
      spendPct
    };
  })
  .sort((a, b) => parseFloat(b.spend) - parseFloat(a.spend));

// ── Najlepsze segmenty ────────────────────────
const topSegmentByConversions = [...segments]
  .filter(s => s.purchases > 0 || s.leads > 0)
  .sort((a, b) => (b.purchases + b.leads) - (a.purchases + a.leads))[0] || null;

const topSegmentByCTR = [...segments]
  .sort((a, b) => parseFloat(b.ctr) - parseFloat(a.ctr))[0] || null;

const topSegmentBySpend = segments[0] || null;

// ── Analiza płci ──────────────────────────────
const genderEntries = Object.entries(genderStats);
const dominantGender = genderEntries.length > 0
  ? genderEntries.sort((a, b) =>
      parseFloat(b[1].spendPct) - parseFloat(a[1].spendPct)
    )[0][0]
  : 'N/A';

// ── Najlepsza grupa wiekowa ───────────────────
const topAgeByConversions = Object.entries(ageSorted)
  .filter(([, d]) => d.purchases > 0 || d.leads > 0)
  .sort((a, b) =>
    (b[1].purchases + b[1].leads) - (a[1].purchases + a[1].leads)
  )[0]?.[0] || 'N/A';

const topAgeByROI = Object.entries(ageSorted)
  .filter(([, d]) => parseFloat(d.cpa) > 0)
  .sort((a, b) =>
    parseFloat(a[1].cpa) - parseFloat(b[1].cpa)
  )[0]?.[0] || 'N/A';

console.log(`Meta Demografia: ${Object.keys(ageSorted).length} grup wiekowych | ${Object.keys(genderStats).length} płci | ${segments.length} segmentów`);

return [{
  json: {
    ...dates,

    metaDemographics: {
      // Globalne sumy
      totalSpend:       totalSpend.toFixed(2),
      totalImpressions,
      totalClicks,
      totalReach,
      totalPurchases:   Math.round(totalPurchases),
      totalLeads:       Math.round(totalLeads),

      // Dane per wiek (posortowane)
      ageBreakdown: ageSorted,

      // Dane per płeć
      genderBreakdown: genderStats,

      // Segmenty wiek + płeć
      segments,
      topSegments: segments.slice(0, 10),

      // Najlepsze segmenty
      topSegmentByConversions,
      topSegmentByCTR,
      topSegmentBySpend,

      // Wnioski
      dominantGender,
      topAgeByConversions,
      topAgeByROI,

      // Liczniki
      ageGroupCount:  Object.keys(ageSorted).length,
      segmentCount:   segments.length
    }
  }
}];

// TESTOWE DANE GOOGLE ADS — świetny ROAS, niskie CPA
return [{
  json: {
    results: [
      {
        campaign: {
          id:     "111001",
          name:   "Brand — Kampania Główna PL",
          status: "ENABLED"
        },
        metrics: {
          clicks:            "3240",
          impressions:       "58000",
          cost_micros:       "8100000000",
          conversions:       "312",
          conversions_value: "78000"
        }
      },
      {
        campaign: {
          id:     "111002",
          name:   "Produkty — Shopping Performance Max",
          status: "ENABLED"
        },
        metrics: {
          clicks:            "4890",
          impressions:       "112000",
          cost_micros:       "12200000000",
          conversions:       "428",
          conversions_value: "107000"
        }
      },
      {
        campaign: {
          id:     "111003",
          name:   "Remarketing — Porzucone Koszyki",
          status: "ENABLED"
        },
        metrics: {
