if (!htmlRaw) {
  throw new Error('Brak htmlReport w danych wejściowych!');
}

console.log(`Długość HTML: ${htmlRaw.length} znaków`);

// Payload jako obiekt JS — N8N sam go poprawnie zserializuje
return [{
  json: {
    ...data,
    pdfPayload: {
      html:            htmlRaw,
      apiKey:          'jVO7DYyykiaxyKlXiXWp5nsWqJswbFv85ineAvDt3H0a2cqkt1JTtcghJDJ0O1EP',
      format:          'A4',
      landscape:       false,
      margin: {
        top:    '0mm',
