        left:   '0mm',
        right:  '0mm'
      },
      printBackground: true,
      scale:           0.95
    }
  }
}];

const raw = item.json.message?.content || item.json.content || item.json.text || "";

// 1. usuń markdown ``` ```
let cleaned = raw
  .replace(/```json\s*/gi, '')
  .replace(/```/g, '')
  .trim();

// 2. spróbuj znaleźć JSON w środku (najważniejsze!)
const match = cleaned.match(/\{[\s\S]*\}/);

let parsed;

if (match) {
  try {
    parsed = JSON.parse(match[0]);
  } catch (e) {
    parsed = {
      error: "JSON parse failed",
      extracted: match[0],
      original: raw
    };
  }
} else {
  parsed = {
    error: "No JSON found",
    original: raw
  };
}

return { json: parsed };

