// ============================================
// ZNAJDŹ TASK PO EMAILU NADAWCY
// ============================================

const incomingEmail = $('📬 Gmail Trigger — Odpowiedzi Klientów').item.json.From || '';
const emailMatch = incomingEmail.match(/[\w.-]+@[\w.-]+\.[a-z]{2,}/i);
const senderEmail = emailMatch ? emailMatch[0].toLowerCase() : '';

const subject = $('📬 Gmail Trigger — Odpowiedzi Klientów').item.json.Subject || '';
const snippet = $('📬 Gmail Trigger — Odpowiedzi Klientów').item.json.snippet || '';

const tasks = item.json.tasks || [];

const EMAIL_FIELD_ID = 'eb65134e-d02b-45cd-94b0-6faad6e613a3';

let foundTask = null;
let matchMethod = null;

for (const task of tasks) {
  // Sprawdź status - szukamy tasków które czekają na akceptację
  const taskStatus = task.status?.status?.toLowerCase() || '';
  if (!taskStatus.includes('czeka') && !taskStatus.includes('akceptac')) continue;

  const fields = task.custom_fields || [];
  const emailField = fields.find(f => f.id === EMAIL_FIELD_ID);
  const taskEmail = (emailField?.value || '').toLowerCase();

  if (taskEmail && senderEmail && taskEmail === senderEmail) {
    foundTask = task;
    matchMethod = 'email_exact';
    break;
  }

  // Fallback: szukaj po temacie maila
  const cleanSubject = subject
    .replace(/^(Re:|Odp:|Fwd:|FW:|Tr:|AW:)\s*/gi, '')
    .trim()
    .toLowerCase();
  const taskName = (task.name || '').toLowerCase();

  if (cleanSubject.length > 10 && taskName.includes(cleanSubject.substring(0, 25))) {
    foundTask = task;
    matchMethod = 'subject_match';
  }
}

return {
  json: {
    found: !!foundTask,
    matchMethod,
    taskId: foundTask?.id || null,
    taskName: foundTask?.name || null,
    taskStatus: foundTask?.status?.status || null,
    senderEmail,
    subject,
    snippet
  }
};

// Parsuj odpowiedź AI
const raw = item.json.message?.content || '';
const match = raw.match(/\{[\s\S]*\}/);

let parsed = {
  decyzja: 'NIEJASNA',
  pewnosc: 0,
  uzasadnienie: 'Błąd parsowania',
  kluczowe_slowa: []
};

if (match) {
  try {
    parsed = JSON.parse(match[0]);
  } catch(e) {
    parsed.uzasadnienie = 'Błąd JSON: ' + e.message;
  }
}

// Pobierz dane z poprzednich węzłów
const taskData = $('🔍 Dopasuj Email do Taska').item.json;
const emailData = $('📬 Gmail Trigger — Odpowiedzi Klientów').item.json;

return {
  json: {
    decyzja: parsed.decyzja || 'NIEJASNA',
    pewnosc: parsed.pewnosc || 0,
    uzasadnienie: parsed.uzasadnienie || '',
    kluczowe_slowa: parsed.kluczowe_slowa || [],
    taskId: taskData.taskId,
    taskName: taskData.taskName,
    senderEmail: taskData.senderEmail,
    subject: emailData.Subject || '',
    snippet: emailData.snippet || '',
    timestamp: new Date().toISOString()
  }
};

