    const config = client.platforms[platKey];
    const aid = config.accountId || config.customerId || config.propertyId || config.brandId;
    if (aid) {
      if (accountIdIndex[aid]) {
        throw new Error('[ClientRegistry] Account ID ' + aid + ' assigned to multiple clients!');
      }
      accountIdIndex[aid] = client.clientId;
    }
