    safeFloat(plats.bingAds    && plats.bingAds.totalRevenue);

  var blendedROAS = totalSpend > 0 ? totalConvValue / totalSpend : 0;

  grandTotalSpend       += totalSpend;
  grandTotalConversions += totalConv;
  grandTotalConvValue   += totalConvValue;
  grandTotalSessions    += safeInt(plats.googleAnalytics && plats.googleAnalytics.totalSessions);
  grandTotalReach       += safeInt(plats.metaAds         && plats.metaAds.totalReach);
  grandTotalFollowers   += safeInt(plats.metricool       && plats.metricool.totalFollowers);
  grandTotalGAds        += gaSpend;
  grandTotalMeta        += metaSpend;
  grandTotalBing        += bingSpend;

  platformTotals.googleAds.spend       += gaSpend;
  platformTotals.googleAds.conversions += safeInt(plats.googleAds  && plats.googleAds.totalConversions);
  platformTotals.googleAds.clicks      += safeInt(plats.googleAds  && plats.googleAds.totalClicks);
  platformTotals.googleAds.impressions += safeInt(plats.googleAds  && plats.googleAds.totalImpressions);

  platformTotals.googleAnalytics.sessions    += safeInt(plats.googleAnalytics && plats.googleAnalytics.totalSessions);
  platformTotals.googleAnalytics.users       += safeInt(plats.googleAnalytics && plats.googleAnalytics.totalUsers);
  platformTotals.googleAnalytics.conversions += safeInt(plats.googleAnalytics && plats.googleAnalytics.totalConversions);
  platformTotals.googleAnalytics.revenue     += safeFloat(plats.googleAnalytics && plats.googleAnalytics.totalRevenue);

  platformTotals.bingAds.spend       += bingSpend;
  platformTotals.bingAds.conversions += safeInt(plats.bingAds && plats.bingAds.totalConversions);
  platformTotals.bingAds.clicks      += safeInt(plats.bingAds && plats.bingAds.totalClicks);
  platformTotals.bingAds.impressions += safeInt(plats.bingAds && plats.bingAds.totalImpressions);

  platformTotals.metaAds.spend      += metaSpend;
  platformTotals.metaAds.purchases  += safeInt(plats.metaAds && plats.metaAds.totalPurchases);
  platformTotals.metaAds.leads      += safeInt(plats.metaAds && plats.metaAds.totalLeads);
  platformTotals.metaAds.reach      += safeInt(plats.metaAds && plats.metaAds.totalReach);
  platformTotals.metaAds.convValue  += safeFloat(plats.metaAds && plats.metaAds.totalPurchaseValue);

  platformTotals.metricool.reach       += safeInt(plats.metricool && plats.metricool.totalReach);
  platformTotals.metricool.engagements += safeInt(plats.metricool && plats.metricool.totalEngagements);
  platformTotals.metricool.followers   += safeInt(plats.metricool && plats.metricool.totalFollowers);
  platformTotals.metricool.posts       += safeInt(plats.metricool && plats.metricool.totalPosts);

  if (!ownerMap[owner]) {
    ownerMap[owner] = { owner: owner, clientCount: 0, clients: [], totalSpend: 0, totalConversions: 0, totalConvValue: 0, totalSessions: 0 };
  }
  ownerMap[owner].clientCount      += 1;
  ownerMap[owner].totalSpend       += totalSpend;
  ownerMap[owner].totalConversions += totalConv;
  ownerMap[owner].totalConvValue   += totalConvValue;
  ownerMap[owner].totalSessions    += safeInt(plats.googleAnalytics && plats.googleAnalytics.totalSessions);
  ownerMap[owner].clients.push({ clientId: cid, clientName: cname, totalSpend: totalSpend.toFixed(2), blendedROAS: blendedROAS.toFixed(2) });

  clientDetails.push({
    clientId:       cid,
    clientName:     cname,
    owner:          owner,
    currency:       report.currency,
    totalSpend:     totalSpend.toFixed(2),
    totalConversions: totalConv,
    totalConvValue: totalConvValue.toFixed(2),
    blendedROAS:    blendedROAS.toFixed(2),
    blendedCPA:     totalConv > 0 ? (totalSpend / totalConv).toFixed(2) : 'N/A',
    googleAdsROAS:  plats.googleAds  && plats.googleAds.ROAS        ? plats.googleAds.ROAS        : 'N/A',
    metaAdsROAS:    plats.metaAds    && plats.metaAds.overallROAS   ? plats.metaAds.overallROAS   : 'N/A',
    webSessions:    safeInt(plats.googleAnalytics && plats.googleAnalytics.totalSessions),
    followers:      safeInt(plats.metricool       && plats.metricool.totalFollowers),
    activePlatforms: report.platformsActive || []
  });
}

