function safeInt(v)   { return parseInt(v)   || 0; }
function safeFloat(v) { return parseFloat(v) || 0; }
function pct(n, d)    { return d > 0 ? ((n / d) * 100).toFixed(2) : '0.00'; }
function divf(n, d)   { return d > 0 ? (n / d).toFixed(2) : '0.00'; }

function getAction(actions, type) {
  if (!Array.isArray(actions)) return 0;
  var found = actions.find(function(a) { return a.action_type === type; });
  return found ? safeFloat(found.value) : 0;
}

function findBySource(src) {
  return allItems.filter(function(i) { return i.json._source === src; });
}

var googleAdsItems   = findBySource('googleAds');
var gaItems          = findBySource('googleAnalytics');
var bingItems        = findBySource('bingAds');
var metaCampItems    = findBySource('metaCampaigns');
var metaPlatItems    = findBySource('metaPlatforms');
var metaDemoItems    = findBySource('metaDemographics');
