  grandTotalConversions += totalConv;
  grandTotalConvValue   += totalConvValue;
  grandTotalSessions    += safeInt(plats.googleAnalytics && plats.googleAnalytics.totalSessions);
  grandTotalReach       += safeInt(plats.metaAds         && plats.metaAds.totalReach);
  grandTotalFollowers   += safeInt(plats.metricool       && plats.metricool.totalFollowers);
  grandTotalGAds        += gaSpend;
  grandTotalMeta        += metaSpend;
  grandTotalBing        += bingSpend;

  platformTotals.googleAds.spend       += gaSpend;
  platformTotals.googleAds.conversions += safeInt(plats.googleAds  && plats.googleAds.totalConversions);
  platformTotals.googleAds.clicks      += safeInt(plats.googleAds  && plats.googleAds.totalClicks);
  platformTotals.googleAds.impressions += safeInt(plats.googleAds  && plats.googleAds.totalImpressions);

  platformTotals.googleAnalytics.sessions    += safeInt(plats.googleAnalytics && plats.googleAnalytics.totalSessions);
  platformTotals.googleAnalytics.users       += safeInt(plats.googleAnalytics && plats.googleAnalytics.totalUsers);
  platformTotals.googleAnalytics.conversions += safeInt(plats.googleAnalytics && plats.googleAnalytics.totalConversions);
  platformTotals.googleAnalytics.revenue     += safeFloat(plats.googleAnalytics && plats.googleAnalytics.totalRevenue);

  platformTotals.bingAds.spend       += bingSpend;
  platformTotals.bingAds.conversions += safeInt(plats.bingAds && plats.bingAds.totalConversions);
  platformTotals.bingAds.clicks      += safeInt(plats.bingAds && plats.bingAds.totalClicks);
  platformTotals.bingAds.impressions += safeInt(plats.bingAds && plats.bingAds.totalImpressions);

  platformTotals.metaAds.spend      += metaSpend;
  platformTotals.metaAds.purchases  += safeInt(plats.metaAds && plats.metaAds.totalPurchases);
  platformTotals.metaAds.leads      += safeInt(plats.metaAds && plats.metaAds.totalLeads);
  platformTotals.metaAds.reach      += safeInt(plats.metaAds && plats.metaAds.totalReach);
  platformTotals.metaAds.convValue  += safeFloat(plats.metaAds && plats.metaAds.totalPurchaseValue);

  platformTotals.metricool.reach       += safeInt(plats.metricool && plats.metricool.totalReach);
  platformTotals.metricool.engagements += safeInt(plats.metricool && plats.metricool.totalEngagements);
  platformTotals.metricool.followers   += safeInt(plats.metricool && plats.metricool.totalFollowers);
  platformTotals.metricool.posts       += safeInt(plats.metricool && plats.metricool.totalPosts);

  if (!ownerMap[owner]) {
    ownerMap[owner] = { owner: owner, clientCount: 0, clients: [], totalSpend: 0, totalConversions: 0, totalConvValue: 0, totalSessions: 0 };
  }
  ownerMap[owner].clientCount      += 1;
  ownerMap[owner].totalSpend       += totalSpend;
  ownerMap[owner].totalConversions += totalConv;
  ownerMap[owner].totalConvValue   += totalConvValue;
  ownerMap[owner].totalSessions    += safeInt(plats.googleAnalytics && plats.googleAnalytics.totalSessions);
  ownerMap[owner].clients.push({ clientId: cid, clientName: cname, totalSpend: totalSpend.toFixed(2), blendedROAS: blendedROAS.toFixed(2) });

  clientDetails.push({
    clientId:       cid,
    clientName:     cname,
    owner:          owner,
    currency:       report.currency,
    totalSpend:     totalSpend.toFixed(2),
    totalConversions: totalConv,
    totalConvValue: totalConvValue.toFixed(2),
    blendedROAS:    blendedROAS.toFixed(2),
    blendedCPA:     totalConv > 0 ? (totalSpend / totalConv).toFixed(2) : 'N/A',
    googleAdsROAS:  plats.googleAds  && plats.googleAds.ROAS        ? plats.googleAds.ROAS        : 'N/A',
    metaAdsROAS:    plats.metaAds    && plats.metaAds.overallROAS   ? plats.metaAds.overallROAS   : 'N/A',
    webSessions:    safeInt(plats.googleAnalytics && plats.googleAnalytics.totalSessions),
    followers:      safeInt(plats.metricool       && plats.metricool.totalFollowers),
    activePlatforms: report.platformsActive || []
  });
}

var ownerBreakdown = Object.values(ownerMap).map(function(o) {
  return Object.assign({}, o, {
    totalSpend:     o.totalSpend.toFixed(2),
    totalConvValue: o.totalConvValue.toFixed(2),
    blendedROAS:    divf(o.totalConvValue, o.totalSpend),
    spendPct:       pctf(o.totalSpend, grandTotalSpend)
  });
});

var rankBySpend       = clientDetails.slice().sort(function(a, b) { return parseFloat(b.totalSpend)       - parseFloat(a.totalSpend); });
var rankByROAS        = clientDetails.filter(function(c) { return parseFloat(c.blendedROAS) > 0; }).sort(function(a, b) { return parseFloat(b.blendedROAS) - parseFloat(a.blendedROAS); });
var rankByConversions = clientDetails.slice().sort(function(a, b) { return b.totalConversions             - a.totalConversions; });

var alerts = [];
for (var ai = 0; ai < clientDetails.length; ai++) {
  var c = clientDetails[ai];
  if (parseFloat(c.blendedROAS) > 0 && parseFloat(c.blendedROAS) < 1.0) {
    alerts.push({ level: 'HIGH', clientId: c.clientId, client: c.clientName, owner: c.owner, issue: 'Blended ROAS below 1.0 (' + c.blendedROAS + 'x) — spending more than earning' });
  }
  if (parseFloat(c.totalSpend) > 0 && c.totalConversions === 0) {
    alerts.push({ level: 'MEDIUM', clientId: c.clientId, client: c.clientName, owner: c.owner, issue: 'Zero conversions despite ' + c.totalSpend + ' spend' });
  }
  if ((c.activePlatforms || []).length === 0) {
    alerts.push({ level: 'LOW', clientId: c.clientId, client: c.clientName, owner: c.owner, issue: 'No active platforms detected' });
  }
}

var dates = $('Date Preparation1').first().json;

var adminReport = {
  reportType:   'ADMIN_GLOBAL_OVERVIEW',
  reportId:     'ADMIN_' + dates.startDate + '_' + dates.endDate,
  period: {
    start: dates.startDate,
    end:   dates.endDate,
    label: dates.monthLabel
  },
  generatedAt:  new Date().toISOString(),
  clientCount:  clientReports.length,
  clientIds:    clientDetails.map(function(c) { return c.clientId; }),
  grandTotals: {
    totalAdSpend:         grandTotalSpend.toFixed(2),
    totalConversions:     grandTotalConversions,
    totalConversionValue: grandTotalConvValue.toFixed(2),
    blendedROAS:          divf(grandTotalConvValue, grandTotalSpend),
    blendedCPA:           divf(grandTotalSpend, grandTotalConversions),
    totalWebSessions:     grandTotalSessions,
    totalPaidReach:       grandTotalReach,
    totalSocialFollowers: grandTotalFollowers,
    googleAdsSpend:       grandTotalGAds.toFixed(2),
    metaAdsSpend:         grandTotalMeta.toFixed(2),
    bingAdsSpend:         grandTotalBing.toFixed(2),
    googleAdsPct:         pctf(grandTotalGAds, grandTotalSpend),
    metaAdsPct:           pctf(grandTotalMeta, grandTotalSpend),
    bingAdsPct:           pctf(grandTotalBing, grandTotalSpend)
  },
  platformSummary: {
    googleAds: Object.assign({}, platformTotals.googleAds, {
      totalSpend: platformTotals.googleAds.spend.toFixed(2),
      avgCTR:     pctf(platformTotals.googleAds.clicks, platformTotals.googleAds.impressions)
    }),
    googleAnalytics: Object.assign({}, platformTotals.googleAnalytics, {
      totalRevenue: platformTotals.googleAnalytics.revenue.toFixed(2)
    }),
    bingAds: Object.assign({}, platformTotals.bingAds, {
      totalSpend: platformTotals.bingAds.spend.toFixed(2),
      avgCTR:     pctf(platformTotals.bingAds.clicks, platformTotals.bingAds.impressions)
    }),
    metaAds: Object.assign({}, platformTotals.metaAds, {
      totalSpend:     platformTotals.metaAds.spend.toFixed(2),
      totalConvValue: platformTotals.metaAds.convValue.toFixed(2),
      overallROAS:    divf(platformTotals.metaAds.convValue, platformTotals.metaAds.spend)
    }),
    metricool: platformTotals.metricool
  },
  clientDetails:  clientDetails,
  rankings: {
    bySpend:        rankBySpend,
    byROAS:         rankByROAS,
    byConversions:  rankByConversions
  },
  ownerBreakdown: ownerBreakdown,
  alerts: {
    count:  alerts.length,
    items:  alerts,
    high:   alerts.filter(function(a) { return a.level === 'HIGH';   }),
    medium: alerts.filter(function(a) { return a.level === 'MEDIUM'; }),
    low:    alerts.filter(function(a) { return a.level === 'LOW';    })
  }
};

console.log('[AdminAgg] Complete. Clients: ' + clientReports.length + ', Total Spend: ' + grandTotalSpend.toFixed(2) + ', Blended ROAS: ' + divf(grandTotalConvValue, grandTotalSpend) + 'x, Alerts: ' + alerts.length);

return [{ json: adminReport }];

var err = $input.first().json;
console.error('[GlobalError] ' + JSON.stringify(err));
return [{ json: { errorType: 'WORKFLOW_ERROR', message: (err && err.message) || 'Unknown error', timestamp: new Date().toISOString(), workflow: 'Multi-Client Marketing Aggregator' } }];
